  "inlineSchema": "// This is the database schema for Solar Panel Management System\n// It defines all tables and relationships for the app\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../lib/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\" // SQLite for local dev, can switch to PostgreSQL for production\n}\n\n// EQUIPOS DE TRABAJO - Teams that install solar panels\nmodel Team {\n  id          String   @id @default(cuid())\n  name        String   @unique // e.g., \"Equipo A\", \"Equipo B\"\n  description String?\n  hourlyRate  Float    @default(45.0) // € per hour\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // Relations\n  projectAssignments ProjectTeamAssignment[]\n  workHours          WorkHours[]\n}\n\n// CLIENTES - Customer information\nmodel Client {\n  id         String   @id @default(cuid())\n  name       String\n  email      String?\n  phone      String?\n  address    String?\n  city       String?\n  province   String?\n  postalCode String?\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  // Relations\n  projects Project[]\n}\n\n// PROYECTOS - Installation projects\nmodel Project {\n  id          String  @id @default(cuid())\n  name        String\n  description String?\n  clientId    String\n  status      String  @default(\"planificado\") // planificado, en_curso, completado, pausado\n  location    String? // Installation address\n\n  // Budget and costs\n  estimatedHours Float // Hours we estimate to complete\n  actualHours    Float @default(0) // Real hours used\n  estimatedCost  Float // Budget cost\n  actualCost     Float @default(0) // Real cost\n\n  // Schedule\n  startDate DateTime?\n  endDate   DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  client          Client                  @relation(fields: [clientId], references: [id], onDelete: Cascade)\n  teamAssignments ProjectTeamAssignment[]\n  materialsUsed   MaterialsInProject[]\n  workHours       WorkHours[]\n}\n\n// MATERIALES - Products/Materials in inventory\nmodel Material {\n  id          String   @id @default(cuid())\n  name        String\n  code        String   @unique // e.g., \"PANEL-450W\", \"CABLE-4MM\"\n  category    String // e.g., \"paneles_solares\", \"cables\", \"soportes\"\n  description String?\n  unitPrice   Float // € per unit\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // Relations\n  inventoryItems InventoryItem[]\n  projectUsage   MaterialsInProject[]\n  movements      InventoryMovement[]  @relation(\"MaterialMovements\")\n}\n\n// INVENTARIO - Current stock levels\nmodel InventoryItem {\n  id           String   @id @default(cuid())\n  materialId   String\n  quantity     Int      @default(0) // Units in stock\n  location     String? // Physical location in warehouse (e.g., \"A-12\", \"B-5\")\n  minThreshold Int      @default(5) // Minimum quantity alert\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Relations\n  material Material @relation(fields: [materialId], references: [id], onDelete: Cascade)\n\n  @@unique([materialId])\n}\n\n// MOVIMIENTOS DE ALMACEN - Inventory history (in/out)\nmodel InventoryMovement {\n  id         String   @id @default(cuid())\n  materialId String\n  type       String // \"entrada\" (in) or \"salida\" (out)\n  quantity   Int\n  reason     String? // e.g., \"Compra proveedor\", \"Proyecto 123\", \"Devolución\"\n  reference  String? // e.g., Project ID, Purchase order\n  date       DateTime @default(now())\n  createdBy  String? // User who created the movement\n  createdAt  DateTime @default(now())\n\n  // Relations\n  material Material @relation(\"MaterialMovements\", fields: [materialId], references: [id], onDelete: Cascade)\n\n  @@index([materialId])\n  @@index([date])\n}\n\n// ASIGNACIÓN DE EQUIPOS A PROYECTOS\nmodel ProjectTeamAssignment {\n  id           String   @id @default(cuid())\n  projectId    String\n  teamId       String\n  role         String? // e.g., \"principal\", \"soporte\"\n  assignedDate DateTime @default(now())\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Relations\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  team    Team    @relation(fields: [teamId], references: [id], onDelete: Cascade)\n\n  @@unique([projectId, teamId])\n}\n\n// REGISTRO DE HORAS - Time tracking\nmodel WorkHours {\n  id          String   @id @default(cuid())\n  teamId      String\n  projectId   String\n  hoursWorked Float // e.g., 8.5 hours\n  date        DateTime // Date of work\n  description String? // What was done\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // Relations\n  team    Team    @relation(fields: [teamId], references: [id], onDelete: Cascade)\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n\n  @@index([projectId])\n  @@index([teamId])\n  @@index([date])\n}\n\n// MATERIALES USADOS EN PROYECTO\nmodel MaterialsInProject {\n  id           String   @id @default(cuid())\n  projectId    String\n  materialId   String\n  quantityUsed Int // Units consumed\n  date         DateTime @default(now())\n  createdAt    DateTime @default(now())\n\n  // Relations\n  project  Project  @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  material Material @relation(fields: [materialId], references: [id], onDelete: Cascade)\n\n  @@index([projectId])\n  @@index([materialId])\n}\n",
